// Enriquecer contratos con datos del cliente
const jsonC  = $('GET Contratos WisPro').first().json;
const jsonCl = $input.first().json;

const contratos = Array.isArray(jsonC)  ? jsonC  : (jsonC?.data  ?? jsonC?.results  ?? jsonC?.contracts ?? []);
const clientes  = Array.isArray(jsonCl) ? jsonCl : (jsonCl?.data ?? jsonCl?.results ?? jsonCl?.clients  ?? []);

const clientMap = {};
clientes.forEach(cl => {
  if (cl.id)        clientMap[String(cl.id)]        = cl;
  if (cl.public_id) clientMap[String(cl.public_id)] = cl;
});

const lista = contratos.map(c => ({
  ...c,
  _cliente: clientMap[String(c.client_id)] || null,
}));

return [{ json: { data: lista, count: lista.length } }];

// Resetear suspension_enviada para contratos que volvieron a estar activos
const input = $input.first().json;
const lista = Array.isArray(input) ? input : (input?.data ?? []);

const activosIds = lista
  .filter(c => (c.state || c.status) === 'enabled')
  .map(c => String(c.id));

if (activosIds.length === 0) return [{ json: { reseteados: 0 } }];

const res = await fetch(
  `https://vgwbqbzpjlbkmxtfghdm.supabase.co/rest/v1/wispro_clientes_config?contrato_id=in.(${activosIds.join(',')})&suspension_enviada=eq.true`,
  {
    method: 'PATCH',
    headers: {
      'apikey': 'sb_publishable_sC_66p4UKHUudDVyWyNcyA_bkrl_J2_',
      'Authorization': 'Bearer sb_publishable_sC_66p4UKHUudDVyWyNcyA_bkrl_J2_',
      'Content-Type': 'application/json',
      'Prefer': 'return=minimal'
    },
    body: JSON.stringify({ suspension_enviada: false, suspension_enviada_at: null })
  }
);

return [{ json: { reseteados: activosIds.length, status: res.status } }];

// Evalúa qué contratos necesitan notificación hoy
const input = $input.first().json;
const lista = Array.isArray(input) ? input : (input?.data ?? input?.results ?? []);

const hoy = new Date();
hoy.setHours(0,0,0,0);

const candidatos = [];

for (const c of lista) {
  const fechaVencStr = c.due_date || c.expiration_date || c.next_due_date || "";
  if (!fechaVencStr) continue;

  const fechaVenc = new Date(fechaVencStr);
  fechaVenc.setHours(0,0,0,0);

  const diasVencido = Math.floor((hoy - fechaVenc) / (1000 * 60 * 60 * 24));
  const estado      = c.state || c.status || "";
  const deuda       = parseFloat(c.balance || c.debt || c.amount_due || 0);

  const cl     = c._cliente || {};
  const nombre = cl.name || cl.full_name ||
    [cl.first_name, cl.last_name].filter(Boolean).join(" ") ||
    c.subscriber?.name || c.name || "";

  const tel = cl.phone_mobile || cl.phone || cl.mobile || cl.telephone ||
    c.subscriber?.phone || c.phone || "";

  if (diasVencido === 2 && deuda > 0 && estado !== "disabled") {
    candidatos.push({ contrato: c, tipo: "recordatorio_1", diasVencido, deuda, tel, nombre });
  } else if (diasVencido === 5 && deuda > 0) {
    candidatos.push({ contrato: c, tipo: "recordatorio_2", diasVencido, deuda, tel, nombre });
  } else if (diasVencido === 7 && deuda > 0) {
    candidatos.push({ contrato: c, tipo: "recordatorio_3", diasVencido, deuda, tel, nombre });
  } else if (estado === "disabled" && deuda > 0) {
    candidatos.push({ contrato: c, tipo: "suspension", diasVencido, deuda, tel, nombre });
  }
}

return candidatos.map(c => ({ json: c }));

const contratoActual = $input.first().json;
const candidato      = $('evaluar-candidatos').item.json;

const cData = contratoActual?.data?.[0] || contratoActual;
const deudaActual  = parseFloat(cData.balance || cData.debt || cData.amount_due || 0);
const estadoActual = cData.state || cData.status || "";

let tel = candidato.tel || "";
tel = tel.replace(/\D/g, "");
if (tel && !tel.startsWith("51")) tel = "51" + tel;

if (deudaActual <= 0) {
  return [{ json: { ...candidato, accion: "saltado_pago", tel, deudaActual } }];
}

if (candidato.tipo === "suspension" && estadoActual !== "disabled") {
  return [{ json: { ...candidato, accion: "saltado_estado", tel, deudaActual } }];
}

return [{ json: { ...candidato, accion: "enviar", tel, deudaActual } }];

